   223→
   224→    // Upload to R2
   225→    const formData = new FormData();
   226→    formData.append('file', req.file.buffer, {
   227→      filename: req.file.originalname,
   228→      contentType: req.file.mimetype
   229→    });
   230→
   231→    const uploadRes = await fetch('https://polsia.com/api/proxy/r2/upload', {
   232→      method: 'POST',
   233→      headers: {
   234→        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
   235→        ...formData.getHeaders()
   236→      },
   237→      body: formData
   238→    });
   239→
   240→    const uploadResult = await uploadRes.json();
   241→    if (!uploadResult.success) {
