   254→      INSERT INTO candidate_profiles (user_id, resume_url)
   255→      VALUES ($1, $2)
   256→      ON CONFLICT (user_id) DO UPDATE SET resume_url = $2, updated_at = NOW()
   257→    `, [req.user.id, uploadResult.file.url]);
   258→
   259→    // Extract text from the resume (supports PDF, DOCX, and plain text)
   260→    let parsedData = null;
   261→    try {
   262→      // Extract text from the file buffer
   263→      const resumeText = await extractTextFromFile(req.file.buffer, req.file.mimetype);
