   990→    );
   991→
   992→    const experience = await pool.query(
   993→      'SELECT title FROM work_experience WHERE user_id = $1 ORDER BY start_date DESC LIMIT 3',
   994→      [req.user.id]
   995→    );
   996→
   997→    // Get active jobs
   998→    const jobs = await pool.query(`
   999→      SELECT j.*, u.company_name as posted_by_company
  1000→      FROM jobs j
  1001→      LEFT JOIN users u ON j.user_id = u.id
  1002→      WHERE j.status = 'active'
  1003→      ORDER BY j.created_at DESC
  1004→      LIMIT $1
  1005→    `, [limit]);
  1006→
  1007→    const candidateProfile = {
  1008→      ...profile.rows[0],
  1009→      skills: skills.rows,
  1010→      titles: experience.rows.map(e => e.title)
  1011→    };
  1012→
  1013→    // Calculate match scores for each job
  1014→    const user = await pool.query('SELECT stripe_subscription_id FROM users WHERE id = $1', [req.user.id]);
