// Matching & Ranking Engine Migration
// Adds vector embeddings and matching infrastructure for intelligent job-candidate matching

module.exports = {
  name: '008_matching_engine',
  up: async (client) => {
    // Enable pgvector extension for vector similarity search
    await client.query(`CREATE EXTENSION IF NOT EXISTS vector`);

    // Candidate embeddings - semantic representation of candidate profiles
    await client.query(`
      CREATE TABLE IF NOT EXISTS candidate_embeddings (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE UNIQUE,
        embedding vector(1536),
        profile_text TEXT,
        skills_summary TEXT,
        experience_summary TEXT,
        last_updated TIMESTAMP DEFAULT NOW(),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Job embeddings - semantic representation of job postings
    await client.query(`
      CREATE TABLE IF NOT EXISTS job_embeddings (
        id SERIAL PRIMARY KEY,
        job_id INTEGER REFERENCES jobs(id) ON DELETE CASCADE UNIQUE,
        embedding vector(1536),
        job_text TEXT,
        requirements_summary TEXT,
        last_updated TIMESTAMP DEFAULT NOW(),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Match results - cached matching scores with explanations
    await client.query(`
      CREATE TABLE IF NOT EXISTS match_results (
        id SERIAL PRIMARY KEY,
        candidate_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        job_id INTEGER REFERENCES jobs(id) ON DELETE CASCADE,
        similarity_score DECIMAL(5,4),
        weighted_score DECIMAL(5,2),
        omniscore_at_match INTEGER,
        trustscore_at_match INTEGER,
        matching_skills JSONB DEFAULT '[]',
        missing_skills JSONB DEFAULT '[]',
        match_explanation JSONB,
        match_level VARCHAR(50),
        calculated_at TIMESTAMP DEFAULT NOW(),
        UNIQUE(candidate_id, job_id)
      )
    `);

    // Job recommendations - personalized job feed for candidates
    await client.query(`
      CREATE TABLE IF NOT EXISTS job_recommendations (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        job_id INTEGER REFERENCES jobs(id) ON DELETE CASCADE,
        match_score DECIMAL(5,2),
        recommendation_reason TEXT,
        shown_at TIMESTAMP,
        clicked_at TIMESTAMP,
        applied_at TIMESTAMP,
        dismissed_at TIMESTAMP,
        created_at TIMESTAMP DEFAULT NOW(),
        UNIQUE(user_id, job_id)
      )
    `);

    // Create indexes for performance
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_candidate_embeddings_user ON candidate_embeddings(user_id);
      CREATE INDEX IF NOT EXISTS idx_job_embeddings_job ON job_embeddings(job_id);
      CREATE INDEX IF NOT EXISTS idx_match_results_candidate ON match_results(candidate_id);
      CREATE INDEX IF NOT EXISTS idx_match_results_job ON match_results(job_id);
      CREATE INDEX IF NOT EXISTS idx_match_results_score ON match_results(weighted_score DESC);
      CREATE INDEX IF NOT EXISTS idx_job_recommendations_user ON job_recommendations(user_id);
      CREATE INDEX IF NOT EXISTS idx_job_recommendations_score ON job_recommendations(match_score DESC);
    `);

    // Create vector similarity index (IVFFlat for faster similarity search)
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_candidate_embeddings_vector
      ON candidate_embeddings USING ivfflat (embedding vector_cosine_ops)
      WITH (lists = 100)
    `);

    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_job_embeddings_vector
      ON job_embeddings USING ivfflat (embedding vector_cosine_ops)
      WITH (lists = 100)
    `);

    console.log('Matching engine tables created successfully');
  }
};

import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import { Textarea } from '@/components/ui/textarea'
import { Input } from '@/components/ui/input'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  ArrowLeft, Users, Star, Calendar, Search,
  Mail, FileText, Send, CheckCircle, Clock, Gift, MessageSquare,
} from 'lucide-react'

interface JobInfo {
  id: number
  title: string
  screening_questions?: string | ScreeningQuestion[]
}

interface ScreeningQuestion {
  id?: string
  question: string
  type?: string
  required?: boolean
  category?: string
}

interface Applicant {
  id: number
  candidate_id: number
  job_id: number
  status: string
  candidate_name: string
  candidate_email: string
  applied_at: string
  updated_at: string
  match_score?: number
  omniscore_at_apply?: number
  current_omniscore?: number
  score_tier?: string
  cover_letter?: string
  screening_answers?: string
  recruiter_notes?: string
}

const statuses = ['applied', 'reviewing', 'shortlisted', 'interviewed', 'offered', 'hired', 'rejected']

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive' }> = {
  applied: { label: 'New', variant: 'secondary' },
  reviewing: { label: 'Reviewing', variant: 'warning' },
  shortlisted: { label: 'Shortlisted', variant: 'default' },
  interviewed: { label: 'Interviewed', variant: 'default' },
  offered: { label: 'Offered', variant: 'success' },
  hired: { label: 'Hired', variant: 'success' },
  rejected: { label: 'Rejected', variant: 'destructive' },
}

export function RecruiterJobApplicantsPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const [job, setJob] = useState<JobInfo | null>(null)
  const [applicants, setApplicants] = useState<Applicant[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [searchQuery, setSearchQuery] = useState('')
  const [selected, setSelected] = useState<Applicant | null>(null)
  const [notes, setNotes] = useState('')
  const [updating, setUpdating] = useState(false)

  useEffect(() => {
    loadApplicants()
  }, [id])

  async function loadApplicants() {
    try {
      const data = await apiCall<{ job: JobInfo; applications: Applicant[] }>(
        `/recruiter/jobs/${id}/applications`
      )
      setJob(data.job)
      setApplicants(data.applications || [])
    } catch {
      navigate('/recruiter/jobs')
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(appId: number, newStatus: string) {
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${appId}`, {
        method: 'PUT',
        body: { status: newStatus, recruiter_notes: notes || undefined },
      })
      loadApplicants()
      if (selected?.id === appId) {
        setSelected(prev => prev ? { ...prev, status: newStatus } : null)
      }
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  // Parse screening questions from job to get labels
  const jobScreeningQuestions: ScreeningQuestion[] = (() => {
    if (!job?.screening_questions) return []
    try {
      const raw = typeof job.screening_questions === 'string'
        ? JSON.parse(job.screening_questions)
        : job.screening_questions
      return Array.isArray(raw) ? raw : []
    } catch {
      return []
    }
  })()

  // Get question label by key (e.g. "sq_default_1" or "q0")
  function getQuestionLabel(key: string, index: number): string {
    // Try matching by id
    const byId = jobScreeningQuestions.find(q => q.id === key)
    if (byId) return byId.question

    // Try matching by index (q0, q1...)
    const match = key.match(/^q(\d+)$/)
    if (match) {
      const qIndex = parseInt(match[1])
      if (jobScreeningQuestions[qIndex]) return jobScreeningQuestions[qIndex].question
    }

    return `Question ${index + 1}`
  }

  const filtered = applicants.filter(a => {
    const matchStatus = !statusFilter || a.status === statusFilter
    const matchSearch = !searchQuery ||
      a.candidate_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      a.candidate_email?.toLowerCase().includes(searchQuery.toLowerCase())
    return matchStatus && matchSearch
  })

  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applicants.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)} months ago`
  }

  function renderScreeningAnswers(answersRaw?: string) {
    if (!answersRaw) return null
    try {
      const answers = typeof answersRaw === 'string' ? JSON.parse(answersRaw) : answersRaw
      if (!answers || Object.keys(answers).length === 0) return null

      return (
        <div>
          <h4 className="font-medium text-sm mb-2 flex items-center gap-1">
            <MessageSquare className="h-4 w-4" /> Screening Answers
          </h4>
          <div className="space-y-2">
            {Object.entries(answers).map(([key, value], i) => (
              <div key={key} className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1 font-medium">
                  {getQuestionLabel(key, i)}
                </p>
                <p className="text-sm">{String(value)}</p>
              </div>
            ))}
          </div>
        </div>
      )
    } catch {
      return null
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/recruiter/jobs')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div className="flex-1">
          <h1 className="font-heading text-2xl font-bold">Applicants</h1>
          <p className="text-muted-foreground text-sm">
            {job?.title || 'Job'} &mdash; {applicants.length} applicant{applicants.length !== 1 ? 's' : ''}
          </p>
        </div>
      </div>

      {/* Stats row */}
      <div className="grid gap-3 grid-cols-2 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applicants.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">{statusCounts.applied || 0}</p>
            <p className="text-xs text-muted-foreground">New</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {(statusCounts.reviewing || 0) + (statusCounts.shortlisted || 0)}
            </p>
            <p className="text-xs text-muted-foreground">In Review</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {(statusCounts.offered || 0) + (statusCounts.hired || 0)}
            </p>
            <p className="text-xs text-muted-foreground">Offered/Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Search and filter */}
      <div className="flex flex-col gap-3 sm:flex-row">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search applicants by name or email..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="pl-9"
          />
        </div>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({applicants.length})
        </Button>
        {statuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {/* Applicant list */}
      {filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Users className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">
              {applicants.length === 0 ? 'No applicants yet for this job' : 'No applicants match your filters'}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-2">
          {filtered.map(app => {
            const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const }
            return (
              <Card
                key={app.id}
                className="cursor-pointer transition-shadow hover:shadow-md"
                onClick={() => { setSelected(app); setNotes(app.recruiter_notes || '') }}
              >
                <CardContent className="p-4">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary font-semibold text-sm">
                          {(app.candidate_name || '?')[0].toUpperCase()}
                        </div>
                        <div className="min-w-0">
                          <h3 className="font-semibold text-sm truncate">{app.candidate_name || 'Unknown'}</h3>
                          <p className="text-xs text-muted-foreground flex items-center gap-1 truncate">
                            <Mail className="h-3 w-3 shrink-0" /> {app.candidate_email}
                          </p>
                        </div>
                        <Badge variant={config.variant} className="ml-1 shrink-0">{config.label}</Badge>
                      </div>
                      <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground ml-10">
                        <span className="flex items-center gap-1">
                          <Clock className="h-3 w-3" /> Applied {timeAgo(app.applied_at)}
                        </span>
                        {app.match_score != null && (
                          <span className="flex items-center gap-1 text-primary font-medium">
                            <Star className="h-3 w-3" /> {app.match_score}% match
                          </span>
                        )}
                        {app.current_omniscore != null && (
                          <span className="flex items-center gap-1">
                            OmniScore: {app.current_omniscore}
                          </span>
                        )}
                        {app.cover_letter && (
                          <span className="flex items-center gap-1">
                            <FileText className="h-3 w-3" /> Has cover letter
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <Select
                        value={app.status}
                        onChange={e => {
                          e.stopPropagation()
                          updateStatus(app.id, e.target.value)
                        }}
                        onClick={e => e.stopPropagation()}
                        className="w-32 text-xs"
                      >
                        {statuses.map(s => (
                          <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                        ))}
                      </Select>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )
          })}
        </div>
      )}

      {/* Detail dialog */}
      {selected && (
        <Dialog open={true} onClose={() => setSelected(null)} className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary font-semibold">
                {(selected.candidate_name || '?')[0].toUpperCase()}
              </div>
              <div>
                <div>{selected.candidate_name}</div>
                <p className="text-sm text-muted-foreground font-normal">{selected.candidate_email}</p>
              </div>
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Stats grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Applied</p>
                <p className="font-medium text-sm">{new Date(selected.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Status</p>
                <Badge variant={statusConfig[selected.status]?.variant || 'secondary'} className="mt-0.5">
                  {statusConfig[selected.status]?.label || selected.status}
                </Badge>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Match Score</p>
                <p className="font-medium text-sm">{selected.match_score != null ? `${selected.match_score}%` : 'N/A'}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">OmniScore</p>
                <p className="font-medium text-sm">{selected.current_omniscore || selected.omniscore_at_apply || 'N/A'}</p>
              </div>
            </div>

            {/* Cover letter */}
            {selected.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1 flex items-center gap-1">
                  <FileText className="h-4 w-4" /> Cover Letter
                </h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap leading-relaxed">
                  {selected.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers - now with actual question labels */}
            {renderScreeningAnswers(selected.screening_answers)}

            {/* Recruiter notes */}
            <div>
              <h4 className="font-medium text-sm mb-1">Recruiter Notes</h4>
              <Textarea
                value={notes}
                onChange={e => setNotes(e.target.value)}
                placeholder="Add notes about this candidate..."
                rows={3}
              />
            </div>

            {/* Status controls */}
            <div className="flex items-center gap-3 pt-2 border-t">
              <span className="text-sm font-medium">Status:</span>
              <Select
                value={selected.status}
                onChange={e => updateStatus(selected.id, e.target.value)}
                className="w-40"
                disabled={updating}
              >
                {statuses.map(s => (
                  <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                ))}
              </Select>
              <Button
                size="sm"
                onClick={() => {
                  updateStatus(selected.id, selected.status)
                  setSelected(null)
                }}
                disabled={updating}
              >
                Save & Close
              </Button>
            </div>

            {/* Make Offer button */}
            {!['rejected', 'offered', 'hired'].includes(selected.status) && (
              <Button
                className="w-full gap-2"
                onClick={() => {
                  navigate(`/recruiter/offers?create=1&candidateId=${selected.candidate_id}&jobId=${id}`)
                }}
              >
                <Gift className="h-4 w-4" /> Make Offer to {selected.candidate_name?.split(' ')[0] || 'Candidate'}
              </Button>
            )}
          </div>
        </Dialog>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import {
  Briefcase, MapPin, DollarSign, Clock, Search, Building2, ArrowRight,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  poster_company?: string
  description: string
  requirements: string
  location: string
  salary_range: string
  job_type: string
  status: string
  created_at: string
  screening_questions?: string
}

export function CandidateJobsPage() {
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [typeFilter, setTypeFilter] = useState('')
  const [locationFilter, setLocationFilter] = useState('')

  useEffect(() => {
    loadJobs()
  }, [])

  async function loadJobs() {
    try {
      const data = await apiCall<{ jobs: Job[] }>('/jobs?status=active&limit=100')
      setJobs(data.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  const filtered = jobs.filter(j => {
    const matchSearch = !search ||
      j.title?.toLowerCase().includes(search.toLowerCase()) ||
      j.company?.toLowerCase().includes(search.toLowerCase()) ||
      j.description?.toLowerCase().includes(search.toLowerCase())
    const matchType = !typeFilter || j.job_type === typeFilter
    const matchLocation = !locationFilter || j.location?.toLowerCase().includes(locationFilter.toLowerCase())
    return matchSearch && matchType && matchLocation
  })

  const jobTypes = [...new Set(jobs.map(j => j.job_type).filter(Boolean))]

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)} months ago`
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">Job Board</h1>
        <p className="text-muted-foreground">Find your next opportunity</p>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col gap-3 sm:flex-row">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Search jobs by title, company, or keywords..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="pl-9"
              />
            </div>
            <Select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className="sm:w-40">
              <option value="">All Types</option>
              {jobTypes.map(t => <option key={t} value={t}>{t}</option>)}
            </Select>
            <Input
              placeholder="Location..."
              value={locationFilter}
              onChange={e => setLocationFilter(e.target.value)}
              className="sm:w-40"
            />
          </div>
        </CardContent>
      </Card>

      {/* Results count */}
      <p className="text-sm text-muted-foreground">{filtered.length} jobs found</p>

      {/* Job list */}
      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No jobs found matching your criteria</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map(job => (
            <Link key={job.id} to={`/candidate/jobs/${job.id}`}>
              <Card className="transition-shadow hover:shadow-md cursor-pointer">
                <CardContent className="p-5">
                  <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-semibold text-base truncate">{job.title}</h3>
                        {(() => {
                          try {
                            return job.screening_questions && JSON.parse(job.screening_questions).length > 0
                          } catch { return false }
                        })() && (
                          <Badge variant="outline" className="text-[10px] shrink-0">Screening</Badge>
                        )}
                      </div>
                      <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground mb-2">
                        <span className="flex items-center gap-1">
                          <Building2 className="h-3.5 w-3.5" />
                          {job.company || job.poster_company || 'Company'}
                        </span>
                        {job.location && (
                          <span className="flex items-center gap-1">
                            <MapPin className="h-3.5 w-3.5" />
                            {job.location}
                          </span>
                        )}
                        {job.salary_range && (
                          <span className="flex items-center gap-1">
                            <DollarSign className="h-3.5 w-3.5" />
                            {job.salary_range}
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-muted-foreground line-clamp-2">
                        {job.description?.substring(0, 200)}
                      </p>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <div className="flex flex-col items-end gap-1">
                        {job.job_type && <Badge variant="secondary">{job.job_type}</Badge>}
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <Clock className="h-3 w-3" />
                          {timeAgo(job.created_at)}
                        </span>
                      </div>
                      <ArrowRight className="h-4 w-4 text-muted-foreground" />
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { useAuth } from '@/contexts/auth-context'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select } from '@/components/ui/select'
import {
  ArrowLeft, MapPin, DollarSign, Building2, Clock, Briefcase, Send,
  CheckCircle, AlertCircle, FileText, ListChecks,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  poster_company?: string
  poster_name?: string
  description: string
  requirements: string
  location: string
  salary_range: string
  job_type: string
  screening_questions?: string | ScreeningQuestion[]
  created_at: string
}

interface ScreeningQuestion {
  id?: string
  question: string
  type?: 'text' | 'yes_no' | 'select'
  required?: boolean
  options?: string[]
  placeholder?: string
  category?: string
}

export function CandidateJobDetailPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const { user } = useAuth()
  const [job, setJob] = useState<Job | null>(null)
  const [loading, setLoading] = useState(true)
  const [applying, setApplying] = useState(false)
  const [applied, setApplied] = useState(false)
  const [showApplyForm, setShowApplyForm] = useState(false)
  const [coverLetter, setCoverLetter] = useState('')
  const [screeningAnswers, setScreeningAnswers] = useState<Record<string, string>>({})
  const [errors, setErrors] = useState<Record<string, string>>({})

  useEffect(() => {
    loadJob()
    if (user) checkIfApplied()
  }, [id, user])

  async function loadJob() {
    try {
      const data = await apiCall<{ job: Job }>(`/jobs/${id}`)
      setJob(data.job)
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function checkIfApplied() {
    try {
      const data = await apiCall<{ success: boolean; applications: { job_id: number }[] }>('/candidate/applications')
      if (data.applications?.some(a => a.job_id === Number(id))) {
        setApplied(true)
      }
    } catch {
      // not critical
    }
  }

  const screeningQuestions: ScreeningQuestion[] = (() => {
    if (!job?.screening_questions) return []
    try {
      const raw = typeof job.screening_questions === 'string'
        ? JSON.parse(job.screening_questions)
        : job.screening_questions
      return Array.isArray(raw) ? raw : []
    } catch {
      return []
    }
  })()

  function validateForm(): boolean {
    const newErrors: Record<string, string> = {}
    screeningQuestions.forEach((q, i) => {
      const key = q.id || `q${i}`
      if (q.required && !screeningAnswers[key]?.trim()) {
        newErrors[key] = 'This question is required'
      }
    })
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  async function handleApply() {
    if (!job) return
    if (!validateForm()) return

    setApplying(true)
    try {
      await apiCall(`/candidate/jobs/${job.id}/apply`, {
        method: 'POST',
        body: {
          cover_letter: coverLetter,
          screening_answers: screeningAnswers,
        },
      })
      setApplied(true)
      setShowApplyForm(false)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to apply')
    } finally {
      setApplying(false)
    }
  }

  function updateAnswer(key: string, value: string) {
    setScreeningAnswers(prev => ({ ...prev, [key]: value }))
    if (errors[key]) {
      setErrors(prev => {
        const next = { ...prev }
        delete next[key]
        return next
      })
    }
  }

  function renderScreeningInput(q: ScreeningQuestion, index: number) {
    const key = q.id || `q${index}`
    const value = screeningAnswers[key] || ''
    const error = errors[key]
    const type = q.type || 'text'

    if (type === 'yes_no') {
      return (
        <div className="space-y-1">
          <div className="flex gap-2 mt-1">
            <Button
              type="button"
              variant={value === 'Yes' ? 'default' : 'outline'}
              size="sm"
              onClick={() => updateAnswer(key, 'Yes')}
              className="flex-1"
            >
              Yes
            </Button>
            <Button
              type="button"
              variant={value === 'No' ? 'default' : 'outline'}
              size="sm"
              onClick={() => updateAnswer(key, 'No')}
              className="flex-1"
            >
              No
            </Button>
          </div>
          {error && <p className="text-xs text-destructive flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
        </div>
      )
    }

    if (type === 'select' && q.options?.length) {
      return (
        <div className="space-y-1">
          <Select
            value={value}
            onChange={e => updateAnswer(key, e.target.value)}
            className="mt-1"
          >
            <option value="">Select an option...</option>
            {q.options.map(opt => (
              <option key={opt} value={opt}>{opt}</option>
            ))}
          </Select>
          {error && <p className="text-xs text-destructive flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
        </div>
      )
    }

    // Default: text input
    return (
      <div className="space-y-1">
        <Input
          value={value}
          onChange={e => updateAnswer(key, e.target.value)}
          className="mt-1"
          placeholder={q.placeholder || 'Your answer...'}
        />
        {error && <p className="text-xs text-destructive flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
      </div>
    )
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)} months ago`
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  if (!job) {
    return (
      <div className="py-16 text-center">
        <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
        <p className="text-muted-foreground">Job not found</p>
        <Button variant="ghost" className="mt-4" onClick={() => navigate('/candidate/jobs')}>
          Back to jobs
        </Button>
      </div>
    )
  }

  return (
    <div className="space-y-6 max-w-3xl">
      <Button variant="ghost" size="sm" onClick={() => navigate('/candidate/jobs')} className="gap-1">
        <ArrowLeft className="h-4 w-4" /> Back to jobs
      </Button>

      {/* Job header */}
      <Card>
        <CardContent className="p-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <h1 className="font-heading text-2xl font-bold mb-2">{job.title}</h1>
              <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
                <span className="flex items-center gap-1">
                  <Building2 className="h-4 w-4" />
                  {job.company || job.poster_company || 'Company'}
                </span>
                {job.location && (
                  <span className="flex items-center gap-1">
                    <MapPin className="h-4 w-4" />
                    {job.location}
                  </span>
                )}
                {job.salary_range && (
                  <span className="flex items-center gap-1">
                    <DollarSign className="h-4 w-4" />
                    {job.salary_range}
                  </span>
                )}
                {job.job_type && (
                  <Badge variant="secondary">{job.job_type}</Badge>
                )}
                <span className="flex items-center gap-1 text-xs">
                  <Clock className="h-3 w-3" />
                  Posted {timeAgo(job.created_at)}
                </span>
              </div>
            </div>
            {applied ? (
              <Badge variant="success" className="gap-1 text-sm py-1.5 px-3 shrink-0">
                <CheckCircle className="h-3.5 w-3.5" /> Applied
              </Badge>
            ) : user ? (
              <Button onClick={() => setShowApplyForm(!showApplyForm)} className="gap-2 shrink-0">
                <Send className="h-4 w-4" /> Apply Now
              </Button>
            ) : (
              <Button onClick={() => navigate('/login')} className="gap-2 shrink-0">
                Sign in to Apply
              </Button>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Apply form */}
      {showApplyForm && !applied && (
        <Card className="border-primary/30 shadow-lg">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Send className="h-5 w-5" />
              Apply for {job.title}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-5">
            <div>
              <Label>Cover Letter <span className="text-muted-foreground text-xs">(optional)</span></Label>
              <Textarea
                placeholder="Tell the employer why you're a great fit for this role..."
                value={coverLetter}
                onChange={e => setCoverLetter(e.target.value)}
                rows={4}
                className="mt-1"
              />
            </div>

            {screeningQuestions.length > 0 && (
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                  <ListChecks className="h-4 w-4 text-primary" />
                  <h4 className="font-medium text-sm">Pre-screening Questions</h4>
                </div>
                {screeningQuestions.map((q, i) => (
                  <div key={q.id || i} className="rounded-lg border p-4 space-y-1">
                    <Label className="text-sm font-medium">
                      {q.question || (typeof q === 'string' ? String(q) : '')}
                      {q.required && <span className="text-destructive ml-1">*</span>}
                    </Label>
                    {q.category && (
                      <p className="text-xs text-muted-foreground capitalize">{q.category.replace(/_/g, ' ')}</p>
                    )}
                    {renderScreeningInput(q, i)}
                  </div>
                ))}
              </div>
            )}

            <div className="flex gap-2 pt-2 border-t">
              <Button onClick={handleApply} disabled={applying} className="gap-2">
                {applying ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <Send className="h-4 w-4" />
                )}
                Submit Application
              </Button>
              <Button variant="outline" onClick={() => setShowApplyForm(false)}>Cancel</Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Description */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Briefcase className="h-5 w-5" /> Job Description
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="prose prose-sm max-w-none whitespace-pre-wrap text-sm leading-relaxed">
            {job.description || 'No description provided.'}
          </div>
        </CardContent>
      </Card>

      {/* Requirements */}
      {job.requirements && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" /> Requirements
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="prose prose-sm max-w-none whitespace-pre-wrap text-sm leading-relaxed">
              {job.requirements}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Screening info */}
      {screeningQuestions.length > 0 && !showApplyForm && !applied && (
        <div className="rounded-lg bg-muted/50 p-4 text-sm text-muted-foreground flex items-center gap-2">
          <ListChecks className="h-4 w-4 shrink-0" />
          This job has {screeningQuestions.length} pre-screening question{screeningQuestions.length > 1 ? 's' : ''} you'll need to answer when applying.
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Dialog, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import {
  FileText, Building2, MapPin, Calendar, ExternalLink, XCircle, AlertTriangle,
  Clock, CheckCircle, Briefcase, DollarSign, Filter, ClipboardList,
  ArrowRight, Eye,
} from 'lucide-react'

interface ScreeningQuestion {
  question: string
  type: 'text' | 'yes_no' | 'select'
  required?: boolean
  options?: string[]
  category?: string
}

interface Application {
  id: number
  job_id: number
  status: string
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  posted_by_company?: string
  applied_at: string
  updated_at: string
  match_score?: number
  cover_letter?: string
  screening_answers?: string | Record<string, string>
  screening_questions?: string | ScreeningQuestion[]
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: typeof Clock }> = {
  applied: { label: 'Applied', variant: 'secondary', icon: FileText },
  reviewing: { label: 'Under Review', variant: 'warning', icon: Eye },
  shortlisted: { label: 'Shortlisted', variant: 'default', icon: CheckCircle },
  interviewed: { label: 'Interviewed', variant: 'default', icon: Briefcase },
  offered: { label: 'Offer Received', variant: 'success', icon: DollarSign },
  hired: { label: 'Hired', variant: 'success', icon: CheckCircle },
  rejected: { label: 'Not Selected', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: XCircle },
}

export function CandidateApplicationsPage() {
  const [applications, setApplications] = useState<Application[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [withdrawTarget, setWithdrawTarget] = useState<Application | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [selectedApp, setSelectedApp] = useState<Application | null>(null)

  useEffect(() => {
    loadApplications()
  }, [])

  async function loadApplications() {
    try {
      const data = await apiCall<{ success: boolean; applications: Application[] }>('/candidate/applications')
      setApplications(data.applications || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function withdrawApplication() {
    if (!withdrawTarget) return
    setWithdrawing(true)
    try {
      await apiCall(`/candidate/applications/${withdrawTarget.id}/withdraw`, {
        method: 'PUT',
      })
      setApplications(prev =>
        prev.map(a => a.id === withdrawTarget.id ? { ...a, status: 'withdrawn' } : a)
      )
      setWithdrawTarget(null)
      setSelectedApp(null)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw application')
    } finally {
      setWithdrawing(false)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return 'Yesterday'
    if (days < 7) return `${days} days ago`
    if (days < 30) return `${Math.floor(days / 7)} weeks ago`
    return `${Math.floor(days / 30)} months ago`
  }

  function parseScreeningData(app: Application) {
    try {
      const answers = typeof app.screening_answers === 'string'
        ? JSON.parse(app.screening_answers)
        : app.screening_answers
      const questions: ScreeningQuestion[] = typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : (app.screening_questions || [])
      return { answers, questions }
    } catch {
      return { answers: null, questions: [] }
    }
  }

  const statuses = ['applied', 'reviewing', 'shortlisted', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn']
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = applications.filter(a => !statusFilter || a.status === statusFilter)

  const active = filtered.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status))
  const completed = filtered.filter(a => ['rejected', 'withdrawn', 'hired'].includes(a.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Applications</h1>
        <p className="text-muted-foreground">Track your job application status and manage active applications</p>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total Applied</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Progress</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offers / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({applications.length})
        </Button>
        {statuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : applications.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">You haven't applied to any jobs yet</p>
            <Link to="/candidate/jobs">
              <Button>Browse Jobs</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Filter className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No applications match this filter</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {active.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Active Applications ({active.length})</h2>
              <div className="space-y-3">
                {active.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onWithdraw={() => setWithdrawTarget(app)}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}

          {completed.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Completed ({completed.length})</h2>
              <div className="space-y-3">
                {completed.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Application detail dialog */}
      {selectedApp && (
        <Dialog open={true} onClose={() => setSelectedApp(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedApp.title}</DialogTitle>
            <DialogDescription>
              {selectedApp.company || selectedApp.posted_by_company || 'Company'}
              {selectedApp.location ? ` • ${selectedApp.location}` : ''}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedApp.status] || { label: selectedApp.status, variant: 'secondary' as const, icon: Clock }
              return <Badge variant={config.variant} className="w-fit">{config.label}</Badge>
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Applied
                </p>
                <p className="font-medium">{new Date(selectedApp.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Clock className="h-3 w-3" /> Last Update
                </p>
                <p className="font-medium">{timeAgo(selectedApp.updated_at)}</p>
              </div>
              {selectedApp.salary_range && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <DollarSign className="h-3 w-3" /> Salary
                  </p>
                  <p className="font-medium">{selectedApp.salary_range}</p>
                </div>
              )}
              {selectedApp.match_score && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground">Match Score</p>
                  <p className="font-medium text-primary">{selectedApp.match_score}%</p>
                </div>
              )}
            </div>

            {/* Progress timeline */}
            <ApplicationTimeline status={selectedApp.status} appliedAt={selectedApp.applied_at} updatedAt={selectedApp.updated_at} />

            {/* Cover letter */}
            {selectedApp.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Your Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selectedApp.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersSection app={selectedApp} parseScreeningData={parseScreeningData} />

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              <Link to={`/candidate/jobs/${selectedApp.job_id}`} className="flex-1">
                <Button variant="outline" className="gap-2 w-full">
                  <ExternalLink className="h-4 w-4" /> View Job
                </Button>
              </Link>
              {!['rejected', 'withdrawn', 'hired'].includes(selectedApp.status) && (
                <Button
                  variant="outline"
                  onClick={() => {
                    setSelectedApp(null)
                    setWithdrawTarget(selectedApp)
                  }}
                  className="gap-2 text-destructive hover:text-destructive"
                >
                  <XCircle className="h-4 w-4" /> Withdraw
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Withdraw confirmation dialog */}
      {withdrawTarget && (
        <Dialog open={true} onClose={() => !withdrawing && setWithdrawTarget(null)} className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              Withdraw Application?
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Are you sure you want to withdraw your application for{' '}
              <strong>{withdrawTarget.title}</strong> at{' '}
              <strong>{withdrawTarget.company || withdrawTarget.posted_by_company || 'this company'}</strong>?
            </p>
            <div className="rounded-lg bg-amber-50 border border-amber-200 p-3 text-sm text-amber-800">
              This action cannot be undone. You may need to reapply if you change your mind.
            </div>
            <div className="flex gap-2 pt-2">
              <Button
                variant="outline"
                onClick={() => setWithdrawTarget(null)}
                disabled={withdrawing}
                className="flex-1"
              >
                Keep Application
              </Button>
              <Button
                variant="destructive"
                onClick={withdrawApplication}
                disabled={withdrawing}
                className="gap-2 flex-1"
              >
                {withdrawing ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <XCircle className="h-4 w-4" />
                )}
                Withdraw
              </Button>
            </div>
          </div>
        </Dialog>
      )}
    </div>
  )
}

function ScreeningAnswersSection({
  app,
  parseScreeningData,
}: {
  app: Application
  parseScreeningData: (app: Application) => { answers: Record<string, string> | null; questions: ScreeningQuestion[] }
}) {
  const { answers, questions } = parseScreeningData(app)

  if (!answers || Object.keys(answers).length === 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
        <ClipboardList className="h-4 w-4 text-primary" />
        Your Screening Answers
      </h4>
      <div className="space-y-2">
        {Object.entries(answers).map(([key, value], i) => {
          const q = questions[i]
          const questionText = q?.question || q || `Question ${i + 1}`
          return (
            <div key={key} className="rounded-lg bg-muted/50 p-3">
              <p className="text-xs text-muted-foreground mb-1 font-medium">
                {String(questionText)}
              </p>
              <p className="text-sm">{String(value)}</p>
            </div>
          )
        })}
      </div>
    </div>
  )
}

function ApplicationTimeline({ status, appliedAt, updatedAt }: { status: string; appliedAt: string; updatedAt: string }) {
  const steps = [
    { key: 'applied', label: 'Applied', icon: FileText },
    { key: 'reviewing', label: 'Review', icon: Eye },
    { key: 'interviewed', label: 'Interview', icon: Briefcase },
    { key: 'offered', label: 'Offer', icon: CheckCircle },
  ]

  const stepIndex = {
    applied: 0, reviewing: 1, shortlisted: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[status] ?? 0

  // Special terminal states
  if (status === 'rejected' || status === 'withdrawn') {
    const config = statusConfig[status]
    return (
      <div>
        <h4 className="font-medium text-sm mb-3">Status Timeline</h4>
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <div className="flex h-8 w-8 items-center justify-center rounded-full border-2 border-primary bg-primary/10">
              <FileText className="h-4 w-4 text-primary" />
            </div>
            <div>
              <p className="text-sm font-medium">Applied</p>
              <p className="text-xs text-muted-foreground">{new Date(appliedAt).toLocaleDateString()}</p>
            </div>
          </div>
          <div className="ml-4 h-4 w-px bg-muted" />
          <div className="flex items-center gap-3">
            <div className={`flex h-8 w-8 items-center justify-center rounded-full border-2 ${
              status === 'rejected' ? 'border-destructive bg-destructive/10' : 'border-muted bg-muted/50'
            }`}>
              <XCircle className={`h-4 w-4 ${status === 'rejected' ? 'text-destructive' : 'text-muted-foreground'}`} />
            </div>
            <div>
              <p className="text-sm font-medium">{config.label}</p>
              <p className="text-xs text-muted-foreground">{new Date(updatedAt).toLocaleDateString()}</p>
            </div>
          </div>
        </div>
      </div>
    )
  }

  if (stepIndex < 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-3">Progress</h4>
      <div className="flex items-center gap-1">
        {steps.map((step, i) => {
          const isComplete = i <= stepIndex
          const isCurrent = i === stepIndex
          const Icon = step.icon
          return (
            <div key={step.key} className="flex items-center gap-1 flex-1">
              <div className={`flex items-center gap-1.5 ${isComplete ? 'text-primary' : 'text-muted-foreground/50'}`}>
                <div className={`flex h-7 w-7 items-center justify-center rounded-full border-2 transition-all ${
                  isCurrent ? 'border-primary bg-primary text-white' :
                  isComplete ? 'border-primary bg-primary/10' : 'border-muted'
                }`}>
                  <Icon className="h-3.5 w-3.5" />
                </div>
                <span className="text-[11px] font-medium hidden sm:inline">{step.label}</span>
              </div>
              {i < steps.length - 1 && (
                <div className={`h-0.5 flex-1 mx-1 ${i < stepIndex ? 'bg-primary' : 'bg-muted'}`} />
              )}
            </div>
          )
        })}
      </div>
      {/* Date labels */}
      <div className="flex justify-between mt-2 px-1">
        <span className="text-[10px] text-muted-foreground">
          {new Date(appliedAt).toLocaleDateString()}
        </span>
        {stepIndex > 0 && (
          <span className="text-[10px] text-muted-foreground">
            Updated {new Date(updatedAt).toLocaleDateString()}
          </span>
        )}
      </div>
    </div>
  )
}

function ApplicationCard({
  app,
  timeAgo,
  onWithdraw,
  onClick,
}: {
  app: Application
  timeAgo: (d: string) => string
  onWithdraw?: () => void
  onClick?: () => void
}) {
  const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const, icon: Clock }

  // Progress steps
  const steps = ['Applied', 'Reviewing', 'Interview', 'Offer']
  const currentStep = {
    applied: 0, reviewing: 1, shortlisted: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[app.status] ?? 0

  // Check if has screening answers
  let hasScreening = false
  try {
    const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers) : app.screening_answers
    hasScreening = answers && Object.keys(answers).length > 0
  } catch { /* ignore */ }

  return (
    <Card
      className="cursor-pointer transition-shadow hover:shadow-md"
      onClick={onClick}
    >
      <CardContent className="p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{app.title}</h3>
              <Badge variant={config.variant}>{config.label}</Badge>
              {hasScreening && (
                <Badge variant="outline" className="gap-1 text-[10px]">
                  <ClipboardList className="h-3 w-3" /> Screening
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {app.company || app.posted_by_company || 'Company'}
              </span>
              {app.location && (
                <span className="flex items-center gap-1">
                  <MapPin className="h-3.5 w-3.5" />
                  {app.location}
                </span>
              )}
              <span className="flex items-center gap-1">
                <Calendar className="h-3.5 w-3.5" />
                Applied {timeAgo(app.applied_at)}
              </span>
              {app.salary_range && (
                <span className="flex items-center gap-1">
                  <DollarSign className="h-3.5 w-3.5" />
                  {app.salary_range}
                </span>
              )}
            </div>

            {/* Progress timeline */}
            {currentStep >= 0 && (
              <div className="mt-3 flex items-center gap-1">
                {steps.map((step, i) => (
                  <div key={step} className="flex items-center gap-1">
                    <div className={`h-2 w-2 rounded-full ${
                      i === currentStep ? 'bg-primary ring-2 ring-primary/30' :
                      i < currentStep ? 'bg-primary' : 'bg-muted'
                    }`} />
                    <span className={`text-[10px] ${i <= currentStep ? 'text-foreground' : 'text-muted-foreground'}`}>
                      {step}
                    </span>
                    {i < steps.length - 1 && (
                      <div className={`h-px w-4 ${i < currentStep ? 'bg-primary' : 'bg-muted'}`} />
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {onWithdraw && !['rejected', 'withdrawn', 'hired'].includes(app.status) && (
              <Button
                variant="ghost"
                size="sm"
                onClick={e => {
                  e.stopPropagation()
                  onWithdraw()
                }}
                className="gap-1 text-muted-foreground hover:text-destructive"
              >
                <XCircle className="h-3.5 w-3.5" /> Withdraw
              </Button>
            )}
            <Link
              to={`/candidate/jobs/${app.job_id}`}
              onClick={e => e.stopPropagation()}
            >
              <Button variant="ghost" size="sm" className="gap-1 shrink-0">
                View Job <ExternalLink className="h-3 w-3" />
              </Button>
            </Link>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Select } from '@/components/ui/select'
import {
  Plus, Briefcase, MapPin, Users, Edit, Trash2, Search, Eye, EyeOff,
  BarChart3, Clock,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  status: string
  created_at: string
  views?: number
  application_count?: number
  interviews?: number
  screening_questions?: string
}

const statusColors: Record<string, 'success' | 'warning' | 'secondary' | 'destructive'> = {
  active: 'success',
  paused: 'warning',
  closed: 'secondary',
  draft: 'secondary',
}

export function RecruiterJobsPage() {
  const navigate = useNavigate()
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [deleting, setDeleting] = useState<number | null>(null)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('')

  useEffect(() => {
    loadJobs()
  }, [])

  async function loadJobs() {
    try {
      const data = await apiCall<{ jobs: Job[] }>('/recruiter/jobs')
      setJobs(data.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function toggleJobStatus(job: Job) {
    const newStatus = job.status === 'active' ? 'paused' : 'active'
    try {
      await apiCall(`/recruiter/jobs/${job.id}`, {
        method: 'PUT',
        body: { status: newStatus },
      })
      loadJobs()
    } catch {
      // silent
    }
  }

  async function deleteJob(id: number) {
    if (!confirm('Are you sure you want to delete this job posting?')) return
    setDeleting(id)
    try {
      await apiCall(`/jobs/${id}`, { method: 'DELETE' })
      loadJobs()
    } catch {
      // silent
    } finally {
      setDeleting(null)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)}mo ago`
  }

  const filtered = jobs.filter(j => {
    const matchSearch = !search ||
      j.title?.toLowerCase().includes(search.toLowerCase()) ||
      j.location?.toLowerCase().includes(search.toLowerCase())
    const matchStatus = !statusFilter || j.status === statusFilter
    return matchSearch && matchStatus
  })

  const activeJobs = jobs.filter(j => j.status === 'active')
  const totalApps = jobs.reduce((sum, j) => sum + (j.application_count || 0), 0)

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">Job Postings</h1>
          <p className="text-muted-foreground text-sm">Manage your job listings</p>
        </div>
        <Link to="/recruiter/jobs/new">
          <Button className="gap-2">
            <Plus className="h-4 w-4" /> Post New Job
          </Button>
        </Link>
      </div>

      {/* Stats */}
      <div className="grid gap-3 grid-cols-3">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">{activeJobs.length}</p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{jobs.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">{totalApps}</p>
            <p className="text-xs text-muted-foreground">Applications</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      {jobs.length > 0 && (
        <div className="flex flex-col gap-3 sm:flex-row">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Search jobs by title or location..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select
            value={statusFilter}
            onChange={e => setStatusFilter(e.target.value)}
            className="sm:w-36"
          >
            <option value="">All Status</option>
            <option value="active">Active</option>
            <option value="paused">Paused</option>
            <option value="closed">Closed</option>
            <option value="draft">Draft</option>
          </Select>
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : jobs.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">No job postings yet</p>
            <Link to="/recruiter/jobs/new">
              <Button className="gap-2"><Plus className="h-4 w-4" /> Create Your First Job</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Search className="mx-auto mb-3 h-8 w-8 opacity-30" />
            <p className="text-muted-foreground">No jobs match your filters</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map(job => (
            <Card key={job.id} className="transition-shadow hover:shadow-sm">
              <CardContent className="p-4">
                <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold truncate">{job.title}</h3>
                      <Badge variant={statusColors[job.status] || 'secondary'}>
                        {job.status}
                      </Badge>
                    </div>
                    <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
                      {job.location && (
                        <span className="flex items-center gap-1">
                          <MapPin className="h-3.5 w-3.5" /> {job.location}
                        </span>
                      )}
                      {job.job_type && <span>{job.job_type}</span>}
                      {job.salary_range && <span>{job.salary_range}</span>}
                      <span className="flex items-center gap-1">
                        <Users className="h-3.5 w-3.5" /> {job.application_count || 0} applicants
                      </span>
                      <span className="flex items-center gap-1 text-xs">
                        <Clock className="h-3 w-3" /> {timeAgo(job.created_at)}
                      </span>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 shrink-0">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => navigate(`/recruiter/jobs/${job.id}/applicants`)}
                      className="gap-1"
                      title="View applicants"
                    >
                      <Users className="h-3.5 w-3.5" />
                      <span className="text-xs">{job.application_count || 0}</span>
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => navigate(`/recruiter/jobs/${job.id}/edit`)}
                      title="Edit job"
                    >
                      <Edit className="h-3.5 w-3.5" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => toggleJobStatus(job)}
                      title={job.status === 'active' ? 'Pause job' : 'Activate job'}
                    >
                      {job.status === 'active' ? (
                        <EyeOff className="h-3.5 w-3.5" />
                      ) : (
                        <Eye className="h-3.5 w-3.5" />
                      )}
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => deleteJob(job.id)}
                      disabled={deleting === job.id}
                      className="text-destructive hover:text-destructive"
                      title="Delete job"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useSearchParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import { Input } from '@/components/ui/input'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { Textarea } from '@/components/ui/textarea'
import {
  FileText, Users, Star, Calendar, MessageSquare, Eye,
  GraduationCap, Gift, Briefcase, Filter, X, Clock,
  ClipboardList, ChevronDown, ChevronUp, ArrowUpDown,
  Brain, TrendingUp, Sparkles, Video,
} from 'lucide-react'

interface Application {
  id: number
  candidate_id: number
  job_id: number
  status: string
  candidate_name: string
  candidate_email: string
  job_title: string
  applied_at: string
  updated_at: string
  match_score?: number
  omniscore_at_apply?: number
  current_omniscore?: number
  score_tier?: string
  cover_letter?: string
  screening_answers?: string
  screening_questions?: string
  recruiter_notes?: string
  verified_skills_count?: number
  best_interview_score?: number
  completed_interviews?: number
}

interface Job {
  id: number
  title: string
  status: string
  application_count?: number
}

const statuses = ['applied', 'reviewing', 'shortlisted', 'interviewed', 'offered', 'hired', 'rejected']

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive' }> = {
  applied: { label: 'New', variant: 'secondary' },
  reviewing: { label: 'Reviewing', variant: 'warning' },
  shortlisted: { label: 'Shortlisted', variant: 'default' },
  interviewed: { label: 'Interviewed', variant: 'default' },
  offered: { label: 'Offered', variant: 'success' },
  hired: { label: 'Hired', variant: 'success' },
  rejected: { label: 'Rejected', variant: 'destructive' },
}

type SortField = 'applied_at' | 'candidate_name' | 'match_score'
type SortDir = 'asc' | 'desc'

export function RecruiterApplicationsPage() {
  const [searchParams, setSearchParams] = useSearchParams()
  const navigate = useNavigate()
  const [applications, setApplications] = useState<Application[]>([])
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [dateFrom, setDateFrom] = useState('')
  const [dateTo, setDateTo] = useState('')
  const [selected, setSelected] = useState<Application | null>(null)
  const [updating, setUpdating] = useState(false)
  const [notes, setNotes] = useState('')
  const [sortField, setSortField] = useState<SortField>('applied_at')
  const [sortDir, setSortDir] = useState<SortDir>('desc')
  const [searchQuery, setSearchQuery] = useState('')

  const jobFilter = searchParams.get('job') || ''

  useEffect(() => {
    loadData()
  }, [jobFilter])

  async function loadData() {
    try {
      const [appsPromise, jobsPromise] = await Promise.allSettled([
        (async () => {
          let url = '/recruiter/applications?limit=200'
          if (jobFilter) url += `&job_id=${jobFilter}`
          return apiCall<{ applications: Application[] }>(url)
        })(),
        apiCall<{ jobs: Job[] }>('/recruiter/jobs'),
      ])

      if (appsPromise.status === 'fulfilled') {
        setApplications(appsPromise.value.applications || [])
      }
      if (jobsPromise.status === 'fulfilled') {
        setJobs(jobsPromise.value.jobs || [])
      }
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(appId: number, newStatus: string) {
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${appId}`, {
        method: 'PUT',
        body: { status: newStatus, recruiter_notes: notes || undefined },
      })
      setApplications(prev =>
        prev.map(a => a.id === appId ? { ...a, status: newStatus } : a)
      )
      if (selected?.id === appId) {
        setSelected(prev => prev ? { ...prev, status: newStatus } : null)
      }
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  async function saveNotes() {
    if (!selected) return
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${selected.id}`, {
        method: 'PUT',
        body: { recruiter_notes: notes },
      })
      setApplications(prev =>
        prev.map(a => a.id === selected.id ? { ...a, recruiter_notes: notes } : a)
      )
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  function setJobFilter(jId: string) {
    if (jId) {
      setSearchParams({ job: jId }, { replace: true })
    } else {
      setSearchParams({}, { replace: true })
    }
  }

  function toggleSort(field: SortField) {
    if (sortField === field) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc')
    } else {
      setSortField(field)
      setSortDir('desc')
    }
  }

  // Apply all filters
  const filtered = applications
    .filter(a => !statusFilter || a.status === statusFilter)
    .filter(a => {
      if (!dateFrom && !dateTo) return true
      const d = new Date(a.applied_at).getTime()
      if (dateFrom && d < new Date(dateFrom).getTime()) return false
      if (dateTo && d > new Date(dateTo + 'T23:59:59').getTime()) return false
      return true
    })
    .filter(a => {
      if (!searchQuery) return true
      const q = searchQuery.toLowerCase()
      return (
        (a.candidate_name || '').toLowerCase().includes(q) ||
        (a.candidate_email || '').toLowerCase().includes(q) ||
        (a.job_title || '').toLowerCase().includes(q)
      )
    })
    .sort((a, b) => {
      let cmp = 0
      if (sortField === 'applied_at') {
        cmp = new Date(a.applied_at).getTime() - new Date(b.applied_at).getTime()
      } else if (sortField === 'candidate_name') {
        cmp = (a.candidate_name || '').localeCompare(b.candidate_name || '')
      } else if (sortField === 'match_score') {
        cmp = (a.match_score || 0) - (b.match_score || 0)
      }
      return sortDir === 'asc' ? cmp : -cmp
    })

  // Group counts
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const selectedJob = jobs.find(j => j.id === Number(jobFilter))
  const hasActiveFilters = statusFilter || dateFrom || dateTo || searchQuery

  function openDetail(app: Application) {
    setSelected(app)
    setNotes(app.recruiter_notes || '')
  }

  function clearAllFilters() {
    setStatusFilter('')
    setDateFrom('')
    setDateTo('')
    setSearchQuery('')
    setJobFilter('')
  }

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between gap-4">
        <div>
          <h1 className="font-heading text-2xl font-bold">Applications</h1>
          <p className="text-muted-foreground">
            Review and manage candidate applications
          </p>
        </div>
        {/* Job filter dropdown */}
        <div className="shrink-0 w-56">
          <Select
            value={jobFilter}
            onChange={e => setJobFilter(e.target.value)}
            className="text-sm"
          >
            <option value="">All Jobs</option>
            {jobs.map(j => (
              <option key={j.id} value={j.id}>{j.title}</option>
            ))}
          </Select>
        </div>
      </div>

      {/* Active job filter banner */}
      {jobFilter && selectedJob && (
        <div className="flex items-center gap-2 rounded-lg bg-primary/5 border border-primary/20 px-4 py-2">
          <Briefcase className="h-4 w-4 text-primary" />
          <span className="text-sm">
            Showing applications for: <strong>{selectedJob.title}</strong>
          </span>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setJobFilter('')}
            className="ml-auto gap-1 h-7"
          >
            <X className="h-3 w-3" /> Clear
          </Button>
        </div>
      )}

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => a.status === 'applied').length}
            </p>
            <p className="text-xs text-muted-foreground">New</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'shortlisted', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Pipeline</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offered / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters section */}
      <div className="space-y-3">
        {/* Search + Date filters row */}
        <div className="flex flex-wrap gap-3 items-end">
          <div className="flex-1 min-w-[200px]">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">Search</label>
            <Input
              placeholder="Search by name, email, or job..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="text-sm"
            />
          </div>
          <div className="w-40">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">From Date</label>
            <Input
              type="date"
              value={dateFrom}
              onChange={e => setDateFrom(e.target.value)}
              className="text-sm"
            />
          </div>
          <div className="w-40">
            <label className="text-xs font-medium text-muted-foreground mb-1 block">To Date</label>
            <Input
              type="date"
              value={dateTo}
              onChange={e => setDateTo(e.target.value)}
              className="text-sm"
            />
          </div>
          {hasActiveFilters && (
            <Button variant="ghost" size="sm" onClick={clearAllFilters} className="gap-1 text-muted-foreground">
              <X className="h-3 w-3" /> Clear Filters
            </Button>
          )}
        </div>

        {/* Status filter pills */}
        <div className="flex flex-wrap gap-2">
          <Button
            variant={!statusFilter ? 'default' : 'outline'}
            size="sm"
            onClick={() => setStatusFilter('')}
          >
            All ({applications.length})
          </Button>
          {statuses.map(s => (
            statusCounts[s] > 0 && (
              <Button
                key={s}
                variant={statusFilter === s ? 'default' : 'outline'}
                size="sm"
                onClick={() => setStatusFilter(s)}
              >
                {statusConfig[s]?.label || s} ({statusCounts[s]})
              </Button>
            )
          ))}
        </div>
      </div>

      {/* Sort controls */}
      <div className="flex items-center gap-3 text-xs text-muted-foreground">
        <span className="font-medium">Sort:</span>
        <SortButton field="applied_at" label="Date" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <SortButton field="candidate_name" label="Name" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <SortButton field="match_score" label="Match" current={sortField} dir={sortDir} onToggle={toggleSort} />
        <span className="ml-auto">{filtered.length} application{filtered.length !== 1 ? 's' : ''}</span>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">
              {applications.length === 0 ? 'No applications yet' : 'No applications match your filters'}
            </p>
            {hasActiveFilters && (
              <Button variant="outline" size="sm" onClick={clearAllFilters} className="mt-3 gap-1">
                <X className="h-3 w-3" /> Clear Filters
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-2">
          {filtered.map(app => {
            const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const }
            return (
              <Card
                key={app.id}
                className="cursor-pointer transition-shadow hover:shadow-md"
                onClick={() => openDetail(app)}
              >
                <CardContent className="p-4">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-semibold truncate">{app.candidate_name || 'Unknown'}</h3>
                        <Badge variant={config.variant}>{config.label}</Badge>
                        {hasScreeningAnswers(app) && (
                          <Badge variant="outline" className="gap-1 text-[10px]">
                            <ClipboardList className="h-3 w-3" /> Screening
                          </Badge>
                        )}
                      </div>
                      <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
                        <span className="flex items-center gap-1">
                          <Briefcase className="h-3 w-3" />
                          {app.job_title}
                        </span>
                        <span>{app.candidate_email}</span>
                        <span className="flex items-center gap-1">
                          <Calendar className="h-3 w-3" />
                          {new Date(app.applied_at).toLocaleDateString()}
                        </span>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 shrink-0">
                      {app.match_score && (
                        <div className="text-center">
                          <div className="text-lg font-bold text-primary">{app.match_score}%</div>
                          <div className="text-[10px] text-muted-foreground">Match</div>
                        </div>
                      )}
                      {app.verified_skills_count !== undefined && app.verified_skills_count > 0 && (
                        <Badge variant="outline" className="gap-1 text-[10px]">
                          <GraduationCap className="h-3 w-3" /> {app.verified_skills_count} verified
                        </Badge>
                      )}
                      <Select
                        value={app.status}
                        onChange={e => {
                          e.stopPropagation()
                          updateStatus(app.id, e.target.value)
                        }}
                        onClick={e => e.stopPropagation()}
                        className="w-32 text-xs"
                      >
                        {statuses.map(s => (
                          <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                        ))}
                      </Select>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )
          })}
        </div>
      )}

      {/* Application detail dialog */}
      {selected && (
        <Dialog open={true} onClose={() => setSelected(null)} className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Application: {selected.candidate_name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Position</p>
                <p className="font-medium">{selected.job_title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Email</p>
                <p className="font-medium text-sm">{selected.candidate_email}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Applied</p>
                <p className="font-medium">{new Date(selected.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Match Score</p>
                <p className="font-medium">{selected.match_score ? `${selected.match_score}%` : 'N/A'}</p>
              </div>
            </div>

            {/* Cover letter */}
            {selected.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selected.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersBlock app={selected} />

            {/* Candidate stats */}
            <div className="flex flex-wrap gap-2">
              {selected.verified_skills_count !== undefined && selected.verified_skills_count > 0 && (
                <Badge variant="outline" className="gap-1">
                  <GraduationCap className="h-3 w-3" /> {selected.verified_skills_count} verified skills
                </Badge>
              )}
              {selected.completed_interviews !== undefined && selected.completed_interviews > 0 && (
                <Badge variant="outline" className="gap-1">
                  <MessageSquare className="h-3 w-3" /> {selected.completed_interviews} interviews done
                </Badge>
              )}
              {selected.current_omniscore && (
                <Badge variant="outline" className="gap-1">
                  <Star className="h-3 w-3" /> OmniScore: {selected.current_omniscore}
                </Badge>
              )}
            </div>

            {/* AI Coaching History */}
            <CandidateCoachingSection candidateId={selected.candidate_id} />

            {/* Notes */}
            <div>
              <h4 className="font-medium text-sm mb-1">Recruiter Notes</h4>
              <Textarea
                value={notes}
                onChange={e => setNotes(e.target.value)}
                placeholder="Add notes about this candidate..."
                rows={3}
              />
            </div>

            {/* Status change + actions */}
            <div className="flex items-center gap-3 pt-2">
              <span className="text-sm font-medium">Status:</span>
              <Select
                value={selected.status}
                onChange={e => updateStatus(selected.id, e.target.value)}
                className="w-40"
                disabled={updating}
              >
                {statuses.map(s => (
                  <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                ))}
              </Select>
              <Button
                size="sm"
                variant="outline"
                onClick={() => {
                  saveNotes()
                  setSelected(null)
                }}
                disabled={updating}
              >
                Save & Close
              </Button>
            </div>

            {/* Make Offer button */}
            {!['rejected', 'offered', 'hired'].includes(selected.status) && (
              <Button
                className="w-full gap-2"
                onClick={() => {
                  navigate(`/recruiter/offers?create=1&candidateId=${selected.candidate_id}&jobId=${selected.job_id}`)
                }}
              >
                <Gift className="h-4 w-4" /> Make Offer to {selected.candidate_name?.split(' ')[0] || 'Candidate'}
              </Button>
            )}
          </div>
        </Dialog>
      )}
    </div>
  )
}

function hasScreeningAnswers(app: Application): boolean {
  try {
    const answers = typeof app.screening_answers === 'string'
      ? JSON.parse(app.screening_answers)
      : app.screening_answers
    return answers && Object.keys(answers).length > 0
  } catch {
    return false
  }
}

function ScreeningAnswersBlock({ app }: { app: Application }) {
  try {
    const answers = typeof app.screening_answers === 'string'
      ? JSON.parse(app.screening_answers)
      : app.screening_answers
    const questions = app.screening_questions
      ? (typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : app.screening_questions)
      : []
    if (!answers || Object.keys(answers).length === 0) return null
    return (
      <div>
        <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
          <ClipboardList className="h-4 w-4 text-primary" />
          Screening Answers
        </h4>
        <div className="space-y-2">
          {Object.entries(answers).map(([key, value], i) => {
            const q = questions[i]
            return (
              <div key={key} className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1 font-medium">
                  {q?.question || q || `Question ${i + 1}`}
                </p>
                <p className="text-sm">{String(value)}</p>
              </div>
            )
          })}
        </div>
      </div>
    )
  } catch {
    return null
  }
}

function CandidateCoachingSection({ candidateId }: { candidateId: number }) {
  const [coaching, setCoaching] = useState<any>(null)
  const [loading, setLoading] = useState(false)
  const [expanded, setExpanded] = useState(false)
  const [expandedSession, setExpandedSession] = useState<number | null>(null)

  useEffect(() => {
    if (!candidateId) return
    setLoading(true)
    apiCall<any>(`/recruiter/candidates/${candidateId}/coaching`)
      .then(res => { if (res.success) setCoaching(res) })
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [candidateId])

  if (loading) return <div className="text-xs text-muted-foreground py-2">Loading coaching data...</div>
  if (!coaching || coaching.stats?.total_sessions === 0) return null

  const stats = coaching.stats
  const scoreColor = (s: number) => s >= 8 ? 'text-green-600' : s >= 6 ? 'text-amber-600' : 'text-red-600'

  return (
    <div>
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full flex items-center justify-between py-1"
      >
        <h4 className="font-medium text-sm flex items-center gap-1.5">
          <Brain className="h-4 w-4 text-primary" />
          AI Coaching History
          <Badge variant="secondary" className="text-xs ml-1">{stats.total_sessions} sessions</Badge>
        </h4>
        {expanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
      </button>

      {expanded && (
        <div className="mt-2 space-y-3">
          {/* Summary stats */}
          <div className="grid grid-cols-4 gap-2">
            <div className="p-2.5 rounded-lg bg-muted/50 text-center">
              <div className={`text-lg font-bold ${stats.average_score ? scoreColor(stats.average_score) : ''}`}>
                {stats.average_score ? `${Math.round(stats.average_score * 10) / 10}` : '-'}
              </div>
              <div className="text-[10px] text-muted-foreground">Avg Score</div>
            </div>
            <div className="p-2.5 rounded-lg bg-muted/50 text-center">
              <div className="text-lg font-bold">{stats.total_sessions}</div>
              <div className="text-[10px] text-muted-foreground">Sessions</div>
            </div>
            <div className="p-2.5 rounded-lg bg-muted/50 text-center">
              <div className={`text-lg font-bold ${stats.highest_score ? scoreColor(stats.highest_score) : ''}`}>
                {stats.highest_score || '-'}
              </div>
              <div className="text-[10px] text-muted-foreground">Best Score</div>
            </div>
            <div className="p-2.5 rounded-lg bg-muted/50 text-center">
              <div className={`text-lg font-bold ${
                stats.improvement_percent != null
                  ? stats.improvement_percent > 0 ? 'text-green-600' : stats.improvement_percent < 0 ? 'text-red-600' : ''
                  : ''
              }`}>
                {stats.improvement_percent != null ? `${stats.improvement_percent > 0 ? '+' : ''}${stats.improvement_percent}%` : '-'}
              </div>
              <div className="text-[10px] text-muted-foreground">Improvement</div>
            </div>
          </div>

          {/* Category breakdown */}
          {coaching.by_category?.length > 0 && (
            <div className="space-y-1.5">
              {coaching.by_category.map((cat: any) => {
                const avg = parseFloat(cat.avg_score) || 0
                const pct = (avg / 10) * 100
                return (
                  <div key={cat.category} className="flex items-center gap-2 text-xs">
                    <span className="w-20 font-medium capitalize">{cat.category}</span>
                    <div className="flex-1 h-2 bg-muted rounded-full overflow-hidden">
                      <div
                        className={`h-full rounded-full ${avg >= 8 ? 'bg-green-500' : avg >= 6 ? 'bg-amber-500' : 'bg-red-500'}`}
                        style={{ width: `${pct}%` }}
                      />
                    </div>
                    <span className={`font-bold ${scoreColor(avg)}`}>{Math.round(avg * 10) / 10}</span>
                    <span className="text-muted-foreground">({cat.count})</span>
                  </div>
                )
              })}
            </div>
          )}

          {/* Recent sessions */}
          <div className="space-y-1.5">
            <h5 className="text-xs font-medium text-muted-foreground">Recent Sessions</h5>
            {coaching.sessions?.slice(0, 5).map((s: any) => {
              const cd = s.coaching_data
              const isExpanded = expandedSession === s.id
              return (
                <div key={s.id} className="rounded-lg border">
                  <button
                    onClick={() => setExpandedSession(isExpanded ? null : s.id)}
                    className="w-full flex items-center gap-2 p-2.5 hover:bg-muted/30 transition-colors text-left"
                  >
                    <div className={`text-sm font-bold ${scoreColor(s.score)}`}>{s.score}/10</div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-medium line-clamp-1">{s.question}</p>
                      <div className="flex items-center gap-1.5 mt-0.5">
                        <Badge variant="outline" className="text-[10px]">
                          {s.response_type === 'video' ? 'Video' : 'Text'}
                        </Badge>
                        <span className="text-[10px] text-muted-foreground">{new Date(s.created_at).toLocaleDateString()}</span>
                      </div>
                    </div>
                    {isExpanded ? <ChevronUp className="h-3.5 w-3.5" /> : <ChevronDown className="h-3.5 w-3.5" />}
                  </button>
                  {isExpanded && cd && (
                    <div className="px-2.5 pb-2.5 space-y-2">
                      {/* Show key feedback */}
                      {(cd.content?.strengths || cd.strengths) && (
                        <div className="p-2 rounded bg-green-50 border border-green-100">
                          <h6 className="text-[10px] font-semibold text-green-800 mb-1">Strengths</h6>
                          <ul className="space-y-0.5">
                            {(cd.content?.strengths || cd.strengths || []).map((s: string, i: number) => (
                              <li key={i} className="text-[10px] text-green-700">{s}</li>
                            ))}
                          </ul>
                        </div>
                      )}
                      {(cd.content?.improvements || cd.improvements) && (
                        <div className="p-2 rounded bg-amber-50 border border-amber-100">
                          <h6 className="text-[10px] font-semibold text-amber-800 mb-1">Areas to Improve</h6>
                          <ul className="space-y-0.5">
                            {(cd.content?.improvements || cd.improvements || []).map((s: string, i: number) => (
                              <li key={i} className="text-[10px] text-amber-700">{s}</li>
                            ))}
                          </ul>
                        </div>
                      )}
                      {cd.communication && (
                        <div className="flex gap-2 text-[10px]">
                          <span className="text-muted-foreground">WPM: <strong>{cd.communication.words_per_minute}</strong></span>
                          <span className="text-muted-foreground">Fillers: <strong>{cd.communication.total_fillers}</strong></span>
                          {cd.presentation && <span className="text-muted-foreground">Presentation: <strong className={scoreColor(cd.presentation.score)}>{cd.presentation.score}/10</strong></span>}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      )}
    </div>
  )
}

function SortButton({
  field,
  label,
  current,
  dir,
  onToggle,
}: {
  field: SortField
  label: string
  current: SortField
  dir: SortDir
  onToggle: (f: SortField) => void
}) {
  const isActive = current === field
  return (
    <button
      onClick={() => onToggle(field)}
      className={`flex items-center gap-1 px-2 py-1 rounded hover:bg-muted transition-colors ${
        isActive ? 'text-foreground font-medium' : ''
      }`}
    >
      {label}
      {isActive ? (
        dir === 'asc' ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />
      ) : (
        <ArrowUpDown className="h-3 w-3 opacity-40" />
      )}
    </button>
  )
}

