             COALESCE(ja.views, 0) as views,
             COALESCE((SELECT COUNT(*) FROM job_applications japp WHERE japp.job_id = j.id), 0) as application_count,
             COALESCE(ja.interviews_scheduled, 0) as interviews
      FROM jobs j

